import{_ as n,o as i,c as t,ag as o}from"./chunks/framework.DXGyWiRo.js";const f=JSON.parse('{"title":"Grammatik Themen","description":"","frontmatter":{"aside":true,"outline":[2,3]},"headers":[],"relativePath":"grammatik.md","filePath":"grammatik.md"}'),a={name:"grammatik.md"};function l(r,e,k,s,h,g){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="grammatik-themen" tabindex="-1">Grammatik Themen <a class="header-anchor" href="#grammatik-themen" aria-label="Permalink to &quot;Grammatik Themen&quot;">​</a></h1><p>Diese Seite bietet eine systematische Übersicht über alle grammatikalischen Themen des Sanskrit-Kurses. Jede der 61 Lektionen ist hier thematisch eingeordnet.</p><h2 id="_1-lautlehre-schrift-samhita-lipi" tabindex="-1">1. Lautlehre &amp; Schrift (Saṃhitā &amp; Lipi) <a class="header-anchor" href="#_1-lautlehre-schrift-samhita-lipi" aria-label="Permalink to &quot;1. Lautlehre &amp; Schrift (Saṃhitā &amp; Lipi)&quot;">​</a></h2><ul><li><strong>Einführung in die Laute</strong>: Systematik und Aussprache -&gt; <a href="/lektionen/lektion01">Lektion 1</a></li><li><strong>Schrifteinführung (Devanāgarī)</strong>: <ul><li>Vokale und einfache Konsonanten -&gt; <a href="/lektionen/lektion40">Lektion 40</a></li><li>Verbundkonsonanten (Ligaturen) -&gt; <a href="/lektionen/lektion41">Lektion 41</a> &amp; <a href="/lektionen/lektion42">Lektion 42</a></li></ul></li><li><strong>Sandhi (Lautverbindung)</strong>: <ul><li>Sandhi von auslautendem <strong>-s/Visarga</strong> -&gt; <a href="/lektionen/lektion02">Lektion 2</a>, <a href="/lektionen/lektion03">Lektion 3</a>, <a href="/lektionen/lektion30">Lektion 30</a></li><li>Sandhi von <strong>-m, -e, -d</strong> -&gt; <a href="/lektionen/lektion04">Lektion 4</a></li><li><strong>Vokalsandhi</strong> -&gt; <a href="/lektionen/lektion03">Lektion 3</a>, <a href="/lektionen/lektion24">Lektion 24</a></li><li>Sandhi von <strong>-n</strong> -&gt; <a href="/lektionen/lektion07">Lektion 7</a></li><li>Sandhi für <strong>Nasale</strong> -&gt; <a href="/lektionen/lektion21">Lektion 21</a>, <a href="/lektionen/lektion26">Lektion 26</a></li><li>Cerebralisation (<strong>n -&gt; ṇ / s -&gt; ṣ</strong>) -&gt; <a href="/lektionen/lektion10">Lektion 10</a>, <a href="/lektionen/lektion26">Lektion 26</a></li><li>Wortsandhi (h-, ch-) -&gt; <a href="/lektionen/lektion44">Lektion 44</a>, <a href="/lektionen/lektion51">Lektion 51</a></li><li><strong>Konsonantensandhi</strong> (Zusammenfassungen) -&gt; <a href="/lektionen/lektion16">Lektion 16</a>, <a href="/lektionen/lektion43">Lektion 43</a></li></ul></li></ul><h2 id="_2-wortkunde-morphologie" tabindex="-1">2. Wortkunde (Morphologie) <a class="header-anchor" href="#_2-wortkunde-morphologie" aria-label="Permalink to &quot;2. Wortkunde (Morphologie)&quot;">​</a></h2><h3 id="_2-1-substantive-und-adjektive-deklination" tabindex="-1">2.1 Substantive und Adjektive (Deklination) <a class="header-anchor" href="#_2-1-substantive-und-adjektive-deklination" aria-label="Permalink to &quot;2.1 Substantive und Adjektive (Deklination)&quot;">​</a></h3><ul><li><strong>Grundlagen</strong>: Kasuslehre -&gt; <a href="/lektionen/lektion01">Lektion 1</a>, <a href="/lektionen/lektion02">Lektion 2</a></li><li><strong>A-Stämme</strong> (Maskulinum &amp; Neutrum) -&gt; <a href="/lektionen/lektion02">Lektion 2</a>, <a href="/lektionen/lektion07">Lektion 7</a></li><li><strong>I- und U-Stämme</strong> -&gt; <a href="/lektionen/lektion03">Lektion 3</a>, <a href="/lektionen/lektion27">Lektion 27</a>, <a href="/lektionen/lektion52">Lektion 52</a></li><li><strong>Konsonantische Stämme</strong>: <ul><li>Stämme auf <strong>-mant / -vant</strong> -&gt; <a href="/lektionen/lektion13">Lektion 13</a></li><li>Stämme auf <strong>-n</strong> (Rājan, Ātman) -&gt; <a href="/lektionen/lektion38">Lektion 38</a></li><li>Einfache Konsonantenstämme -&gt; <a href="/lektionen/lektion51">Lektion 51</a>, <a href="/lektionen/lektion54">Lektion 54</a></li><li>Wurzelnomina auf <strong>-ā, -ī, -ū</strong> -&gt; <a href="/lektionen/lektion61">Lektion 61</a></li></ul></li><li><strong>Der Dual (Zweizahl)</strong> der Nomina -&gt; <a href="/lektionen/lektion49">Lektion 49</a>, <a href="/lektionen/lektion50">Lektion 50</a>, <a href="/lektionen/lektion53">Lektion 53</a></li><li><strong>Zahlen &amp; Steigerung</strong>: <ul><li>Zahlwörter (Kardinalia/Ordinalia) -&gt; <a href="/lektionen/lektion52">Lektion 52</a></li><li>Steigerung (Komparativ/Superlativ) -&gt; <a href="/lektionen/lektion53">Lektion 53</a></li></ul></li></ul><h3 id="_2-2-pronomina-adverbien" tabindex="-1">2.2 Pronomina &amp; Adverbien <a class="header-anchor" href="#_2-2-pronomina-adverbien" aria-label="Permalink to &quot;2.2 Pronomina &amp; Adverbien&quot;">​</a></h3><ul><li><strong>Pronomina</strong>: <ul><li>Frage- und Demonstrativpronomen -&gt; <a href="/lektionen/lektion04">Lektion 4</a></li><li>Relativpronomen (yad) -&gt; <a href="/lektionen/lektion19">Lektion 19</a></li><li>Personalpronomen (1. &amp; 2. Person) -&gt; <a href="/lektionen/lektion46">Lektion 46</a>, <a href="/lektionen/lektion47">Lektion 47</a></li><li>Indefinitpronomina -&gt; <a href="/lektionen/lektion37">Lektion 37</a></li></ul></li><li><strong>Adverbien &amp; Anrede</strong>: <ul><li>Bildung von Adverbien -&gt; <a href="/lektionen/lektion37">Lektion 37</a>, <a href="/lektionen/lektion52">Lektion 52</a></li><li>Höfliche Anrede &amp; Vokativ -&gt; <a href="/lektionen/lektion21">Lektion 21</a>, <a href="/lektionen/lektion44">Lektion 44</a></li></ul></li></ul><h3 id="_2-3-verben-konjugation" tabindex="-1">2.3 Verben (Konjugation) <a class="header-anchor" href="#_2-3-verben-konjugation" aria-label="Permalink to &quot;2.3 Verben (Konjugation)&quot;">​</a></h3><ul><li><strong>Das Präsenssystem (Indikativ)</strong>: <ul><li>Personalendungen (3., 2., 1. Person) -&gt; <a href="/lektionen/lektion06">Lektion 6</a>, <a href="/lektionen/lektion44">Lektion 44</a>, <a href="/lektionen/lektion39">Lektion 39</a></li><li>Thematische Klassen (1, 4, 6, 10) -&gt; <a href="/lektionen/lektion06">Lektion 6</a>, <a href="/lektionen/lektion28">Lektion 28</a></li><li>Athematische Klassen -&gt; <a href="/lektionen/lektion17">Lektion 17</a>, <a href="/lektionen/lektion33">Lektion 33</a>, <a href="/lektionen/lektion07">Lektion 7</a>, <a href="/lektionen/lektion31">Lektion 31</a>, <a href="/lektionen/lektion08">Lektion 8</a>, <a href="/lektionen/lektion30">Lektion 30</a></li></ul></li><li><strong>Andere Tempora &amp; Modi</strong>: <ul><li><strong>Imperfekt</strong> (Vergangenheit) -&gt; <a href="/lektionen/lektion32">Lektion 32</a></li><li><strong>Optativ &amp; Imperativ</strong> -&gt; <a href="/lektionen/lektion30">Lektion 30</a>, <a href="/lektionen/lektion48">Lektion 48</a></li><li><strong>Perfekt</strong> (Singular/Plural) -&gt; <a href="/lektionen/lektion34">Lektion 34</a>, <a href="/lektionen/lektion35">Lektion 35</a>, <a href="/lektionen/lektion36">Lektion 36</a></li><li><strong>Perfekt (Dual)</strong> -&gt; <a href="/lektionen/lektion60">Lektion 60</a></li><li><strong>Futur</strong> (Einfach &amp; Periphrastisch) -&gt; <a href="/lektionen/lektion26">Lektion 26</a>, <a href="/lektionen/lektion61">Lektion 61</a></li><li><strong>Aorist</strong> (Vergangenheit) -&gt; <a href="/lektionen/lektion54">Lektion 54</a>, <a href="/lektionen/lektion55">Lektion 55</a>, <a href="/lektionen/lektion56">Lektion 56</a>, <a href="/lektionen/lektion57">Lektion 57</a>, <a href="/lektionen/lektion58">Lektion 58</a></li></ul></li><li><strong>Abgeleitete Verbformen</strong>: <ul><li><strong>Passiv &amp; Kausativ</strong> -&gt; <a href="/lektionen/lektion10">Lektion 10</a>, <a href="/lektionen/lektion28">Lektion 28</a>, <a href="/lektionen/lektion29">Lektion 29</a></li><li><strong>Intensivum &amp; Denominativa</strong> -&gt; <a href="/lektionen/lektion61">Lektion 61</a></li></ul></li><li><strong>Verben im Dual (Zweizahl)</strong> -&gt; <a href="/lektionen/lektion59">Lektion 59</a>, <a href="/lektionen/lektion60">Lektion 60</a></li></ul><h3 id="_2-4-nominalbildungen-komposita" tabindex="-1">2.4 Nominalbildungen &amp; Komposita <a class="header-anchor" href="#_2-4-nominalbildungen-komposita" aria-label="Permalink to &quot;2.4 Nominalbildungen &amp; Komposita&quot;">​</a></h3><ul><li><strong>Komposita (Samāsa)</strong>: <ul><li><strong>Dvandva</strong> (Kopulativkomposita) -&gt; <a href="/lektionen/lektion05">Lektion 5</a>, <a href="/lektionen/lektion09">Lektion 9</a></li><li><strong>Tatpuruṣa</strong> (Determinativ) -&gt; <a href="/lektionen/lektion15">Lektion 15</a>, <a href="/lektionen/lektion18">Lektion 18</a></li><li>Upapada-Komposita -&gt; <a href="/lektionen/lektion51">Lektion 51</a></li><li><strong>Bahuvrīhi</strong> (Possessiv) -&gt; <a href="/lektionen/lektion20">Lektion 20</a></li></ul></li><li><strong>Suffixe &amp; Partizipien</strong>: <ul><li>Wichtige Suffixe (-a, -ana, -tra, etc.) -&gt; <a href="/lektionen/lektion08">Lektion 8</a>, <a href="/lektionen/lektion09">Lektion 9</a></li><li><strong>PPP</strong> (Partizip Perfekt Passiv) -&gt; <a href="/lektionen/lektion12">Lektion 12</a>, <a href="/lektionen/lektion13">Lektion 13</a></li><li><strong>PPA</strong> (Partizip Perfekt Aktiv) -&gt; <a href="/lektionen/lektion52">Lektion 52</a></li><li><strong>Absolutivum &amp; Infinitiv</strong> -&gt; <a href="/lektionen/lektion22">Lektion 22</a>, <a href="/lektionen/lektion23">Lektion 23</a></li></ul></li></ul><h2 id="_3-satzlehre-syntax" tabindex="-1">3. Satzlehre (Syntax) <a class="header-anchor" href="#_3-satzlehre-syntax" aria-label="Permalink to &quot;3. Satzlehre (Syntax)&quot;">​</a></h2><ul><li><strong>Der Nominalsatz</strong> -&gt; <a href="/lektionen/lektion02">Lektion 2</a></li><li><strong>Der Fragesatz</strong> -&gt; <a href="/lektionen/lektion37">Lektion 37</a></li><li><strong>Kasusgebrauch</strong>: <ul><li>Nominalsatz &amp; Nominativ -&gt; <a href="/lektionen/lektion02">Lektion 2</a></li><li>Akkusativ (auch doppelt) -&gt; <a href="/lektionen/lektion07">Lektion 7</a>, <a href="/lektionen/lektion11">Lektion 11</a></li><li>Instrumentalis -&gt; <a href="/lektionen/lektion10">Lektion 10</a></li><li>Genitiv -&gt; <a href="/lektionen/lektion14">Lektion 14</a></li><li>Dativ -&gt; <a href="/lektionen/lektion24">Lektion 24</a></li><li>Ablativ -&gt; <a href="/lektionen/lektion25">Lektion 25</a></li><li>Lokativ -&gt; <a href="/lektionen/lektion27">Lektion 27</a></li></ul></li><li><strong>Nebensätze</strong>: <ul><li>Relativsätze -&gt; <a href="/lektionen/lektion19">Lektion 19</a></li><li>Gebrauch der Partizipien -&gt; <a href="/lektionen/lektion12">Lektion 12</a>, <a href="/lektionen/lektion44">Lektion 44</a></li></ul></li></ul><h2 id="_4-metrik-verslehre" tabindex="-1">4. Metrik (Verslehre) <a class="header-anchor" href="#_4-metrik-verslehre" aria-label="Permalink to &quot;4. Metrik (Verslehre)&quot;">​</a></h2><p>Sanskrit-Philosophie und Literatur sind oft in Versen verfasst. Die Metrik lehrt den Rhythmus und Aufbau dieser Verse.</p><ul><li><strong>Einführung &amp; Śloka</strong> -&gt; <a href="/lektionen/lektion45">Lektion 45</a>, <a href="/lektionen/lektion53">Lektion 53</a></li><li><strong>Fortgeschrittene Metren</strong> (Trīṣṭubh, Jāgatī) -&gt; <a href="/lektionen/lektion54">Lektion 54</a></li></ul><hr><div class="tip custom-block github-alert"><p class="custom-block-title">Merkregel</p><p>Diese Übersicht hilft dir, gezielt grammatikalische Phänomene nachzuschlagen. Für eine chronologische Erarbeitung des Stoffes folge einfach der Nummerierung der Lektionen im Hauptmenü.</p></div>',20)])])}const m=n(a,[["render",l]]);export{f as __pageData,m as default};
